def check_permission(user, resource, action):
    permissions = {
        "admin": {"view", "edit", "delete"},
        "manager": {"view", "edit"},
        "editor": {"view", "edit"},
        "viewer": {"view"}
    }
    if user.role in permissions and action in permissions[user.role]:
        return True
    if resource.is_restricted and user.role == "admin":
        return True
    return False
