def can_view(resource, role):
    if resource.is_restricted:
        return role == "admin"
    return role in {"manager", "editor", "viewer"}

def can_edit(resource, role):
    return role in {"manager", "editor"}

def can_delete(resource, role):
    return role == "admin"

def check_permission(user, resource, action):
    permission_funcs = {
        "view": can_view,
        "edit": can_edit,
        "delete": can_delete,
    }
    return permission_funcs[action](resource, user.role)
```
